 58	// ResolveTriagePolicy returns the effective triage policy for this config,
 59	// layering any `triage.policies` entries on top of the binary default
 60	// ladders. Unknown failure-mode names and unknown action names are
 61	// silently dropped (schema validation surfaces typos at load time).
 62	func (c *NewConfig) ResolveTriagePolicy() triage.TriagePolicy {
 63		policy := triage.DefaultPolicy()
 64		if c == nil || c.Triage == nil || len(c.Triage.Policies) == 0 {
 65			return policy
 66		}
 67		for modeStr, actionStrs := range c.Triage.Policies {
 68			mode, err := triage.ParseFailureMode(modeStr)
 69			if err != nil {
 70				continue
 71			}
 72			ladder := make([]triage.Action, 0, len(actionStrs))
 73			for _, a := range actionStrs {
 74				act, err := triage.ParseAction(a)
 75				if err != nil {
 76					continue
 77				}
 78				ladder = append(ladder, act)
 79			}
 80			if len(ladder) == 0 {
 81				continue
 82			}
 83			policy.Ladders[mode] = ladder
 84		}
 85		return policy
 86	}
